import { ensureReady, semanticTopK } from './semanticSearch';

const STOP = new Set([
  'the', 'a', 'an', 'of', 'on', 'in', 'to', 'is', 'are', 'was', 'were', 'be',
  'and', 'or', 'for', 'with', 'at', 'by', 'from', 'as', 'it', 'i', 'my', 'me',
  'this', 'that', 'how', 'what', 'we', 'you', 'they', 'but', 'so', 'if', 'into',
  'about', 'out', 'up', 'over', 'than', 'then', 'has', 'have', 'had', 'do',
]);

let itemsPromise = null;

export function searchTokens(query) {
  const all = String(query).toLowerCase().split(/\s+/)
    .map(t => t.replace(/[^\w]+/g, ''))
    .filter(t => t.length >= 2);
  const meaningful = all.filter(t => !STOP.has(t));
  return meaningful.length ? meaningful : all;
}

export async function loadSearchItems() {
  if (!itemsPromise) {
    itemsPromise = fetch('/assets/search-index.json', { cache: 'no-cache' })
      .then((res) => {
        if (!res.ok) throw new Error(`search-index.json ${res.status}`);
        return res.json();
      });
  }
  return itemsPromise;
}

export async function retrieveAskContexts(query, n = 8, existingItems) {
  const items = existingItems && existingItems.length ? existingItems : await loadSearchItems();
  const itemsById = {};
  for (const it of items) itemsById[it.id] = it;

  await ensureReady();
  const sem = await semanticTopK(query, 12);
  const toks = [...new Set(searchTokens(query))].filter(t => t.length >= 3);
  const N = items.length;
  const hays = items.map(it => ({ id: it.id, hay: `${it.title} ${it.body}`.toLowerCase() }));
  const df = {};
  for (const t of toks) df[t] = hays.filter(h => h.hay.includes(t)).length;
  const lex = hays.map(h => {
    let s = 0;
    for (const t of toks) if (df[t] > 0 && h.hay.includes(t)) s += Math.log(1 + N / df[t]);
    return { id: h.id, s };
  }).filter(x => x.s > 0).sort((a, b) => b.s - a.s);

  const K = 60;
  const score = new Map();
  const add = (arr, w) => arr.forEach((x, i) => score.set(x.id, (score.get(x.id) || 0) + w / (K + i)));
  add(lex, 2);
  add(sem.map(h => ({ id: h.id })), 1);

  const rrf = [...score.entries()].sort((a, b) => b[1] - a[1]).map(([id]) => id);
  const forced = lex.slice(0, 3).map(x => x.id);
  const ids = [...new Set([...forced, ...rrf])].slice(0, n);
  return ids.map(id => itemsById[id]).filter(Boolean);
}

function isFragmentItem(item) {
  return item && item.route === '/fragments';
}

function shouldUseFragments(query) {
  const q = String(query || '').toLowerCase();
  const fragmentTerms = [
    'fragment', 'fragments', 'melbourne', 'market', 'queen victoria', 'oyster', 'toast',
    'guangzhou', 'chaoshan', 'hot pot', 'meatball', 'diaolong', 'kitten', 'cat', 'cute',
    'identity', 'taiwanese', 'taiwan', 'shanghai identity', 'label', 'labels', 'memory',
    'satisfaction', 'writing', 'expression', 'recording', 'rule', 'rules', 'goal', 'goals'
  ];
  return fragmentTerms.some(term => q.includes(term));
}

// Ask normally receives all non-fragment site context, but fragments are intentionally
// retrieval-gated. They are personal, expandable notes and should only be injected when
// the user's question is clearly related. For example, a Melbourne question may retrieve
// the Queen Victoria Market fragment, but a general self-introduction should not receive
// identity fragments or idea fragments by default.
export async function allAskContexts(query = '', existingItems) {
  const items = existingItems && existingItems.length ? existingItems : await loadSearchItems();
  const base = items.filter(it => !isFragmentItem(it)).sort((a, b) => (a.id || 0) - (b.id || 0));
  if (!shouldUseFragments(query)) return base;

  const retrieved = await retrieveAskContexts(query, 6, items);
  const fragmentHits = retrieved.filter(isFragmentItem);
  return [...base, ...fragmentHits];
}

export function cleanAskContextText(body) {
  return String(body || '')
    .replace(/^(Research papers[^.]*\.\s*|Hobby, hobbies[^.]*\.\s*)+/i, '')
    .replace(/\s*Years:\s*[\d\s]+\.?\s*$/i, '')
    .trim();
}

export function stripAnswerCitations(answer) {
  return String(answer || '')
    .replace(/\s*,?\s*\bas\s+(?:mentioned|shown|described|noted|stated|indicated|covered|referenced)\s+(?:in|by)\s*(?:\[[\d,\s]+\]\s*(?:(?:,|\band\b|\bor\b)\s*)?)+(?!\w)/gi, '')
    .replace(/\b(?:as\s+)?(?:mentioned|shown|described|noted|stated|indicated|covered|referenced)\s+(?:in|by)\s*(?:\[[\d,\s]+\]\s*(?:(?:,|\band\b|\bor\b)\s*)?)+,?\s*/gi, '')
    .replace(/\s*\[[\d,\s]+\]/g, '')
    .replace(/\s*\[[\d,\s]*$/g, '')
    .replace(/\b(?:as\s+)?(?:mentioned|shown|described|noted|stated|indicated|covered|referenced)\s+(?:in|by)\s+(?:and|or)(?=[\s,.!?]|$)/gi, '')
    .replace(/,\s*([.!?])/g, '$1')
    .replace(/([.!?]),(\s|$)/g, '$1$2')
    .replace(/\s+([,.!?])/g, '$1')
    .replace(/,\s*$/g, '')
    .trim();
}

export function citedSourcesFromAnswer(answer, sources) {
  const numbered = sources.map((s, i) => ({ ...s, n: i + 1 }));
  const cited = new Set();
  const re = /\[([\d,\s]+)\]/g;
  let m;
  while ((m = re.exec(answer))) {
    m[1].split(/[,\s]+/).filter(Boolean).forEach((n) => cited.add(parseInt(n, 10)));
  }
  if (!cited.size) return [];
  return numbered.filter((s) => cited.has(s.n));
}
